"use client";

import { useState } from "react";
import { motion, useMotionValue, useSpring, useTransform, AnimatePresence } from "framer-motion";
import { X } from "lucide-react";
import { projects } from "../config";
import FadeIn from "./ui/FadeIn";

interface Project {
  title: string;
  description: string;
  [key: string]: unknown;
}

function ProjectCard({ project, onClick }: { project: Project; onClick: () => void }) {
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  const mouseXSpring = useSpring(x);
  const mouseYSpring = useSpring(y);

  const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ["15deg", "-15deg"]);
  const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ["-15deg", "15deg"]);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement, MouseEvent>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const width = rect.width;
    const height = rect.height;
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;
    const xPct = mouseX / width - 0.5;
    const yPct = mouseY / height - 0.5;
    x.set(xPct);
    y.set(yPct);
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
  };

  return (
    <motion.div
      style={{ rotateX, rotateY, transformStyle: "preserve-3d" }}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      onClick={onClick}
      className="relative p-6 bg-[#111] rounded-2xl border border-border cursor-pointer hover:border-accent/80 transition-colors h-full flex flex-col group shadow-xl"
      whileHover={{ scale: 1.05 }}
      transition={{ duration: 0.2 }}
    >
      <div 
        className="absolute inset-0 rounded-2xl bg-gradient-to-br from-accent/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" 
        style={{ transform: "translateZ(-20px)" }} 
      />
      <h3 className="text-xl font-bold font-mono mb-3 text-white drop-shadow-md" style={{ transform: "translateZ(40px)" }}>
        {project.title}
      </h3>
      <p className="text-foreground/70 text-sm line-clamp-3 mb-6" style={{ transform: "translateZ(20px)" }}>
        {project.description}
      </p>
      <div className="mt-auto pt-4 border-t border-white/10" style={{ transform: "translateZ(10px)" }}>
        <span className="inline-flex text-accent text-sm font-semibold items-center group-hover:drop-shadow-[0_0_8px_rgba(42,182,115,0.8)] transition-all">
          View Architecture &rarr;
        </span>
      </div>
    </motion.div>
  );
}

export default function Projects() {
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  if (typeof document !== "undefined") {
    if (selectedProject) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "auto";
    }
  }

  return (
    <section id="projects" className="py-24 max-w-6xl mx-auto px-4 relative z-10 w-full">
      <FadeIn>
        <div className="mb-16 text-center">
          <h2 className="text-3xl md:text-5xl font-bold mb-4 text-white">Engineering <span className="text-accent underline decoration-accent/30 decoration-2 underline-offset-4">Projects</span></h2>
          <p className="text-foreground/60 max-w-xl mx-auto">Deep diving into production migrations, optimization schemas, and high-availability solutions.</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8" style={{ perspective: 1200 }}>
          {projects.map((proj, idx) => (
            <FadeIn key={idx} delay={idx * 0.15} direction="up" className="h-full">
              <ProjectCard project={proj} onClick={() => setSelectedProject(proj)} />
            </FadeIn>
          ))}
        </div>
      </FadeIn>

      <AnimatePresence>
        {selectedProject && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setSelectedProject(null)}
              className="absolute inset-0 bg-background/90 backdrop-blur-md"
            />
            <motion.div
              initial={{ opacity: 0, scale: 0.95, y: 30 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95, y: 30 }}
              className="relative w-full max-w-3xl bg-[#111] border border-accent/30 rounded-2xl p-6 md:p-10 shadow-[0_0_50px_rgba(42,182,115,0.15)] overflow-y-auto max-h-[90vh] z-10"
            >
              <button
                onClick={() => setSelectedProject(null)}
                className="absolute top-6 right-6 p-2 rounded-full hover:bg-surface text-foreground/70 transition-colors bg-black/50"
              >
                <X size={20} />
              </button>
              
              <h2 className="text-2xl md:text-3xl font-bold font-mono text-white tracking-tight mb-4 pr-10">
                {selectedProject.title}
              </h2>
              
              <div className="prose prose-invert max-w-none text-foreground/80 leading-relaxed space-y-4">
                <p className="text-base md:text-lg">
                  {selectedProject.description}
                </p>
                {selectedProject.description.includes('MongoDB') && (
                  <div className="mt-8 p-6 bg-black/50 rounded-xl border border-accent/20">
                    <h4 className="font-semibold text-accent font-mono mb-4 flex items-center gap-2">
                       <span className="w-2 h-2 rounded-full bg-accent animate-pulse" /> Technical Execution
                    </h4>
                    <ul className="list-disc list-inside text-sm space-y-2 text-foreground/80 marker:text-accent">
                      <li>Cross-platform topology migration (Windows to Linux).</li>
                      <li>Ensuring replica sets sync state reliably.</li>
                      <li>Datafile consistency validation with zero-data-loss SLAs.</li>
                    </ul>
                  </div>
                )}
                {selectedProject.description.includes('MySQL') && (
                  <div className="mt-8 p-6 bg-black/50 rounded-xl border border-accent/20">
                    <h4 className="font-semibold text-accent font-mono mb-4 flex items-center gap-2">
                       <span className="w-2 h-2 rounded-full bg-accent animate-pulse" /> Technical Execution
                    </h4>
                    <ul className="list-disc list-inside text-sm space-y-2 text-foreground/80 marker:text-accent">
                      <li>Automated Version upgrade testing (5.x to 8.x).</li>
                      <li>Query profiling via Performance Schema and index adjustments.</li>
                      <li>GTID-based replication configurations and ProxySQL routing.</li>
                    </ul>
                  </div>
                )}
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </section>
  );
}
