"use client";

import { motion } from "framer-motion";
import { useState } from "react";

const nodes = [
  { id: "frontend", label: "Frontend", details: "Next.js, Tailwind, React", x: 100, y: 150 },
  { id: "api", label: "API Gateway", details: "Node.js, Express, AWS API Gateway", x: 300, y: 150 },
  { id: "db1", label: "MySQL (Primary)", details: "AWS RDS, MySQL 8.0, High Availability", x: 500, y: 80 },
  { id: "db2", label: "MongoDB (NoSQL)", details: "Replica Set, Document Store", x: 500, y: 220 },
];

const edges = [
  { source: "frontend", target: "api" },
  { source: "api", target: "db1" },
  { source: "api", target: "db2" },
];

export default function SystemDiagram() {
  const [hoveredNode, setHoveredNode] = useState<string | null>(null);

  const getNodeCoords = (id: string) => nodes.find(n => n.id === id);

  return (
    <div className="relative w-full max-w-3xl mx-auto h-[350px] bg-surface rounded-xl border border-border p-4 shadow-2xl overflow-hidden group">
      <svg className="absolute inset-0 w-full h-full" style={{ zIndex: 1 }}>
        <defs>
          <linearGradient id="line-grad" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="#4b5563" />
            <stop offset="100%" stopColor="#2ab673" />
          </linearGradient>
        </defs>
        {edges.map((edge, i) => {
          const source = getNodeCoords(edge.source);
          const target = getNodeCoords(edge.target);
          if (!source || !target) return null;

          return (
            <motion.line
              key={i}
              x1={source.x}
              y1={source.y}
              x2={target.x}
              y2={target.y}
              stroke="url(#line-grad)"
              strokeWidth="2"
              initial={{ pathLength: 0, opacity: 0 }}
              whileInView={{ pathLength: 1, opacity: 0.5 }}
              transition={{ duration: 1.5, delay: i * 0.3 }}
            />
          );
        })}
      </svg>

      {nodes.map((node, i) => (
        <motion.div
          key={node.id}
          className="absolute transform -translate-x-1/2 -translate-y-1/2 cursor-pointer z-10"
          style={{ left: node.x, top: node.y }}
          initial={{ scale: 0, opacity: 0 }}
          whileInView={{ scale: 1, opacity: 1 }}
          transition={{ duration: 0.5, delay: i * 0.2 + 0.5, type: "spring" }}
          onMouseEnter={() => setHoveredNode(node.id)}
          onMouseLeave={() => setHoveredNode(null)}
          whileHover={{ scale: 1.1 }}
        >
          <div className="w-24 h-24 rounded-full bg-[#111] border-2 border-accent flex items-center justify-center shadow-[0_0_15px_rgba(42,182,115,0.3)]">
            <span className="text-white text-sm font-semibold text-center leading-tight p-2">{node.label}</span>
          </div>
          
          {hoveredNode === node.id && (
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="absolute top-full mt-2 w-48 left-1/2 transform -translate-x-1/2 bg-[#222] border border-border text-gray-300 text-xs p-3 rounded-lg shadow-xl z-50 pointer-events-none"
            >
              {node.details}
            </motion.div>
          )}
        </motion.div>
      ))}

      {/* Animated dots moving along the paths */}
      <svg className="absolute inset-0 w-full h-full pointer-events-none" style={{ zIndex: 2 }}>
        {edges.map((edge, i) => {
          const source = getNodeCoords(edge.source);
          const target = getNodeCoords(edge.target);
          if (!source || !target) return null;
          return (
            <motion.circle
              key={`dot-${i}`}
              r="4"
              fill="#2ab673"
              initial={{ cx: source.x, cy: source.y, opacity: 0 }}
              animate={{ cx: target.x, cy: target.y, opacity: [0, 1, 0] }}
              transition={{ duration: 2, repeat: Infinity, delay: i * 0.5, ease: "linear" }}
            />
          );
        })}
      </svg>
    </div>
  );
}
